SELECT COUNT(*)
FROM clothing_goods_sku s

    s.deleted = 0
    AND s.status = #{status}
    AND s.category_id = #{categoryId}
    AND s.color LIKE CONCAT('%', #{color}, '%')
    AND s.size = #{size}
    AND (s.name LIKE CONCAT('%', #{keyword}, '%') OR s.sku_code LIKE CONCAT('%', #{keyword}, '%'))
    AND s.goods_id = #{goodsId}
    AND s.goods_id IS NOT NULL
    AND s.goods_id IS NULL

